const state={mode:'intro',distance:100,sample:250,noise:1.2,channels:20,step:15,phaseNoise:2,tofError:2.5,multipath:25,rttAnimation:true,pbrAnimation:true,csFlowAnimation:true,csFlowStep:-1};
const modes={
 intro:{label:'INTRODUCTION · CHANNEL SOUNDING',title:'Introduction For Channel Sounding',description:'A focused introduction to Bluetooth Channel Sounding, covering the motivation, RF waveform, procedure flow, PBR / RTT principles, ambiguity behavior, and practical deployment considerations.',formula:'Speaker · Jacobs Ting',lab:'',labDesc:''},
 overview:{label:'BLUETOOTH EVOLUTION · 5.0 → 6.0',title:'From longer connectivity to more precise measurement',description:'Bluetooth 5.0 improved range, speed, and advertising capacity; Bluetooth 6.0 adds Channel Sounding so devices can perform standardized, secure, and precise distance sensing.',formula:'Bluetooth 6.0 = Connectivity + Secure Fine Ranging',lab:'',labDesc:''},
 tech:{label:'METER-LEVEL RANGING · TECHNOLOGY MATRIX',title:'Meter-level ranging technology comparison',description:'Compares wireless ranging technologies from RSSI, Wi-Fi RTT, and UWB to Bluetooth Channel Sounding across PHY design, topology, accuracy, and robustness in complex environments.',formula:'Accuracy = f(Bandwidth, Time, Phase, Multipath)',lab:'',labDesc:''},
 market:{label:'GLOBAL RANGING MARKET · 2025 → 2030',title:'Market share and value of ranging technologies',description:'Uses the global indoor positioning and navigation market as the scope, separates existing BLE/Wi-Fi/UWB technologies, and highlights the potential impact of Bluetooth Channel Sounding on precision ranging value.',formula:'Market Value = Installed Base × Ranging Adoption × Solution Revenue',lab:'',labDesc:''},
 csintro:{label:'BLUETOOTH 6.0 · CHANNEL SOUNDING OVERVIEW',title:'Channel Sounding Technology Overview',description:'Bluetooth Channel Sounding is a secure precision ranging feature built on Bluetooth LE connections. It uses multi-frequency phase measurements for high-resolution distance estimates and RTT to establish a secure distance boundary.',formula:'Secure Fine Ranging = PBR Precision + RTT Security',lab:'',labDesc:''},
 cswaveform:{label:'CHANNEL SOUNDING · CS RF WAVEFORM',title:'CS RF Waveform',description:'The CS RF waveform consists of a GFSK packet header followed by a CW tone. The header supports packet synchronization and control information, while the CW tone provides a stable phase reference for PBR phase discrimination between Initiator and Reflector.',formula:'CS waveform = GFSK Header + Phase-discriminating CW Tone',lab:'',labDesc:''},
 cscompare:{label:'CHANNEL SOUNDING · CS vs BR/EDR',title:'Positioning differences between CS and BR/EDR',description:'Channel Sounding and Bluetooth BR/EDR both operate in the 2.4 GHz ISM band, but they are designed for different goals: BR/EDR is a data and audio link PHY, while CS is a secure precision ranging procedure on Bluetooth LE connections.',formula:'BR/EDR = Data Link · CS = Ranging Measurement',lab:'',labDesc:''},
 csflow:{label:'CHANNEL SOUNDING · PROCEDURE TIMELINE',title:'Channel Sounding ranging procedure timeline',description:'A Gantt-style view aligning Initiator, Reflector, and control flow from capability exchange and procedure setup through RTT/PBR RF measurements, data reporting, and distance fusion.',formula:'Setup → CS Sub-events → PBR / RTT → Distance Estimate',lab:'',labDesc:''},
 tof:{label:'MODE 01 · TIME OF FLIGHT',title:'Using time to create an absolute distance scale',description:'The Initiator sends a packet and the Reflector returns it. Half the round-trip time multiplied by the speed of light gives distance. It is not affected by phase periodicity, making it a reliable absolute distance anchor.',formula:'d = c × Δt / 2',lab:'ToF round-trip-time simulator',labDesc:'Adjust true distance, sampling rate, and timing noise to observe changes in the estimated distance.'},
 pbr:{label:'MODE 02 · PHASE-BASED RANGING',title:'Reading centimeter-level distance from phase',description:'The same path accumulates different phase at different carrier frequencies. Comparing phase slope across frequencies converts small phase differences into high-resolution distance estimates.',formula:'d = c × Δφ / (4πΔf)',lab:'PBR frequency and ambiguity simulator',labDesc:'Change frequency step and channel count to observe how candidate peaks spread or converge.'},
 hybrid:{label:'MODE 03 · HYBRID FUSION',title:'Coarse timing bounds the range; fine phase refines the position',description:'ToF first establishes an unambiguous distance window; PBR then selects the periodic candidate inside that window and refines the estimate using phase information.',formula:'d̂ = select(PBR | nearest ToF)',lab:'Hybrid fusion and interference simulator',labDesc:'Increase ToF error and multipath interference to see when the fusion result can still lock onto the correct candidate.'}
 ,usecases:{label:'CHANNEL SOUNDING · APPLICATION SCENARIOS',title:'Channel Sounding application scenarios',description:'Channel Sounding adds trusted distance information to the existing Bluetooth ecosystem. It can work with RFID, access control, vehicle networks, and warehouse systems, upgrading systems from presence detection to precise distance verification.',formula:'Identity + Secure Distance + Context = Trusted Automation',lab:'',labDesc:''}
 ,vendors:{label:'CHANNEL SOUNDING · VENDOR LANDSCAPE',title:'Channel Sounding solutions on the market',description:'Summarizes publicly announced Bluetooth Channel Sounding chips, connectivity platforms, development kits, and software support from major vendors, distinguishing available development solutions, platform integration, and products still awaiting official confirmation.',formula:'Solution = Radio / SoC + Bluetooth 6 Stack + Ranging Algorithm + RF Design',lab:'',labDesc:''}
 ,conclusion:{label:'CONCLUSION · OUTLOOK & CHALLENGES',title:'Channel Sounding outlook and open challenges',description:'Channel Sounding moves Bluetooth from connectivity and coarse proximity into secure precision ranging, but large-scale deployment still depends on the maturity of algorithms, RF design, power consumption, interoperability, and the product ecosystem.',formula:'Mass Adoption = Accuracy × Robustness × Interoperability ÷ Cost',lab:'',labDesc:''}
};
const $=s=>document.querySelector(s);const round=(n,d=2)=>Number(n).toFixed(d);
function range(key,label,min,max,step,unit,minLabel,maxLabel){return `<div class="control"><div class="control-top"><label>${label}</label><output id="${key}-out">${state[key]} ${unit}</output></div><input type="range" data-key="${key}" min="${min}" max="${max}" step="${step}" value="${state[key]}"><div class="range-labels"><span>${minLabel}</span><span>${maxLabel}</span></div></div>`}
function segment(key,label){return `<div class="control"><div class="control-top"><label>${label}</label><output id="${key}-out">${state[key]} channels</output></div><div class="segment"><button data-segment="${key}" data-value="20" class="${state[key]===20?'active':''}">20</button><button data-segment="${key}" data-value="72" class="${state[key]===72?'active':''}">72</button></div></div>`}
function techVisual(){return `<div class="tech-table-wrap"><table class="tech-table"><thead><tr><th>Comparison item</th><th>Bluetooth 5.0<br>RSSI</th><th>Wi‑Fi<br>RTT / FTM</th><th>UWB<br>ToF / TDoA</th><th class="cs-col">Bluetooth 6.0<br>Channel Sounding</th></tr></thead><tbody><tr><th>Band</th><td>2.4 GHz ISM</td><td>2.4/5/6 GHz</td><td>Approx. 3.1–10.6 GHz</td><td class="cs-col">2.4 GHz ISM<br>72 ranging channels</td></tr><tr><th>Modulation</th><td>GFSK<br>LE 1M/2M/Coded PHY</td><td>OFDM/OFDMA<br>depends on 802.11 PHY generation</td><td>HRP UWB: BPSK/BPM‑BPSK pulses</td><td class="cs-col">GFSK packet + ASK tone<br>PBR/RTT dedicated PHY</td></tr><tr><th>Network topology</th><td>Point-to-point, broadcast, and mesh; RSSI can estimate distance from scanners or beacons</td><td>STA-to-AP infrastructure; Wi-Fi Aware peer-to-peer is also possible</td><td>Tag-to-anchor; two-way ranging or multi-anchor TDoA / multilateration</td><td class="cs-col">1:1 Initiator-to-Reflector link built on a BLE ACL connection</td></tr><tr><th>Waveform</th><td>Narrowband packets and FHSS; estimates distance from received power attenuation</td><td>Wideband multicarrier packets; Fine Timing Measurement measures RTT</td><td>Nanosecond ultra-short pulses and ultra-wideband spectrum; directly resolves arrival time</td><td class="cs-col">Measures phase slope across multi-frequency tones with encrypted RTT packets</td></tr><tr><th>Ranging principle</th><td>RSSI → Path-loss model</td><td>Packet round-trip time RTT</td><td>ToF/TDoA/AoA</td><td class="cs-col">PBR fine ranging + RTT distance bounding / security verification</td></tr><tr><th>Typical accuracy</th><td>Approx. 2–10 m<br>often still &gt;1 m after environmental calibration</td><td>Approx. 1–2 m</td><td>Approx. 0.1–0.3 m</td><td class="cs-col"><strong>Approx. ±0.2 m</strong><br>targeting centimeter-level performance</td></tr><tr><th>Multipath robustness</th><td><span class="rating">●○○○</span><br>Low: power is easily affected by blockage and reflections</td><td><span class="rating">●●○○</span><br>Medium: bandwidth helps time resolution, but NLoS can still bias results</td><td><span class="rating high">●●●●</span><br>High: wideband CIR can separate first path and reflections</td><td class="cs-col"><span class="rating high">●●●○</span><br>Medium-high: multi-frequency PBR / multi-antenna paths improve robustness</td></tr><tr><th>Secure ranging</th><td>Low; RSSI can be manipulated through transmit power</td><td>Depends on protocol and implementation; FTM is not specifically designed for secure distance bounding</td><td>High; 802.15.4z STS supports secure ranging</td><td class="cs-col">High; encrypted RTT, randomized sequences, and attack detection mechanisms</td></tr><tr><th>Hardware / power</th><td>Lowest; existing BLE chips can be used</td><td>Higher; requires RTT-capable APs / clients</td><td>Highest; requires an additional UWB radio and antenna</td><td class="cs-col">Low to medium; reuses the 2.4 GHz BLE ecosystem but requires the new CS PHY</td></tr></tbody></table></div><div class="tech-notes"><div class="tech-note"><b>Bluetooth 5.0</b><span>Lowest cost, suitable for presence and coarse proximity.</span></div><div class="tech-note"><b>Wi‑Fi RTT</b><span>Suitable for indoor positioning with existing APs; three or more APs enable multilateration.</span></div><div class="tech-note"><b>UWB</b><span>Best accuracy and multipath resolution, but hardware and deployment cost are higher.</span></div><div class="tech-note"><b>Channel Sounding</b><span>Balances BLE ubiquity, low power, accuracy, and security.</span></div></div><p class="source-note">Accuracy values are typical implementation ranges and are affected by NLoS, antenna design, and algorithms. Sources: <a href="https://www.bluetooth.com/core-specification-6-feature-overview/" target="_blank">Bluetooth SIG Core 6.0</a>, <a href="https://www.bluetooth.com/learn-about-bluetooth/feature-enhancements/channel-sounding/" target="_blank">Channel Sounding</a>, <a href="https://developer.android.com/develop/connectivity/wifi/wifi-rtt" target="_blank">Android Wi‑Fi RTT</a>.</p>`}
function visual(){
  if(state.mode==='intro')return `<section class="title-slide"><div class="title-agenda"><h3>AGENDA</h3><ol><li><b>01</b>From longer connectivity to more precise measurement</li><li><b>02</b>Meter-level ranging technology comparison</li><li><b>03</b>Market share and value of ranging technologies</li><li><b>04</b>Channel Sounding Technology Overview</li><li><b>05</b>Positioning differences between CS and BR/EDR</li><li><b>06</b>CS RF Waveform</li><li><b>07</b>Channel Sounding ranging procedure timeline</li><li><b>08</b>Using time to create an absolute distance scale</li><li><b>09</b>Reading centimeter-level distance from phase</li><li><b>10</b>Coarse timing bounds the range; fine phase refines the position</li><li><b>11</b>Channel Sounding application scenarios</li><li><b>12</b>Channel Sounding solutions on the market</li><li><b>13</b>Channel Sounding outlook and open challenges</li></ol></div></section>`;
  if(state.mode==='overview')return `<div class="version-compare"><article class="version-card"><h3>Bluetooth 5.0</h3><ul><li>2M PHY: Higher data rate</li><li>LE Coded PHY: Longer range</li><li>Extended advertising: larger advertising payloads</li><li>Positioning mainly based on RSSI / AoA / AoD</li><li>Distance estimates are sensitive to environment and multipath</li></ul></article><article class="version-card highlight"><h3>Bluetooth 6.0</h3><ul><li>Extends Bluetooth LE connectivity</li><li>Adds standardized Channel Sounding ranging</li><li>Supports both ToF and PBR ranging methods</li><li>Centimeter-level precision and stronger relay-attack resistance</li><li>Applies to digital keys, Find My, and indoor positioning</li></ul></article></div><div class="cs-highlight"><b>CHANNEL SOUNDING · Core upgrade</b><p>Channel Sounding no longer guesses distance from signal strength alone. It measures packet flight time and multi-frequency phase differences. ToF provides unambiguous absolute distance, while PBR provides high resolution; together they deliver uniqueness, precision, and security.</p></div>`;
  if(state.mode==='tof')return `<div class="rtt-visual" aria-label="RTT round-trip measurement animation"><div class="rtt-head"><span>INITIATOR <i class="badge">A</i></span><div class="rtt-head-center"><b class="distance">${state.distance} m</b><label class="rtt-toggle"><input type="checkbox" data-rtt-animation ${state.rttAnimation?'checked':''}><span></span><em>Animation</em></label></div><span>REFLECTOR <i class="badge">B</i></span></div><div class="rtt-stage"><div class="rtt-device rtt-device-a"><strong>A</strong><small>TX / RX timestamp</small></div><div class="rtt-track"><span class="rtt-pulse"></span><span class="rtt-echo"></span></div><div class="rtt-device rtt-device-b"><strong>B</strong><small>Reflect response</small></div></div><div class="rtt-steps"><span class="rtt-step step-tx"><i>1</i>Transmit packet</span><span class="rtt-step step-reflect"><i>2</i>Reflect response</span><span class="rtt-step step-rx"><i>3</i>Receive packet</span></div><p class="rtt-note">RTT measures the packet round-trip delay. The Initiator subtracts known processing time, divides the flight time by two, then converts it into distance.</p></div>`;
	  if(state.mode==='pbr')return pbrVisual();
  return `<div class="fusion-flow"><div class="fusion-box"><b>TOF</b><span>Absolute distance</span><small>Coarse, but unique</small></div><i class="fusion-op">+</i><div class="fusion-box"><b>PBR</b><span>Phase distance</span><small>Precise, but ambiguous</small></div><i class="fusion-op">→</i><div class="fusion-box"><b>HYBRID</b><span>Unique precise solution</span><small>Robust + high resolution</small></div></div>`;
}
function feature(){return state.mode==='overview'?`<small>WHY IT MATTERS</small><h3>Bluetooth gains native precision ranging for the first time</h3><p>Unlike RSSI, which is easily affected by blockage, reflections, and transmit power, Channel Sounding estimates distance from physical time and phase measurements and improves reliability through multi-channel measurements.</p>`:state.mode==='tof'?`<small>Core characteristic</small><h3>No distance ambiguity</h3><p>The limitation is that time-measurement resolution depends on sampling rate and clock synchronization; faster sampling produces finer distance quantization.</p>`:state.mode==='pbr'?`<small>Core limitation</small><h3>2π periodic ambiguity</h3><p>A larger frequency step Δf reduces the unambiguous distance Dmax. More channels provide more evidence to converge periodic candidates to a unique solution.</p>`:''}
function controls(){
  const measureButton=`<button class="measure">▶ Run one measurement</button>`;
  if(state.mode==='tof')return range('distance','True distance',1,200,1,'m','1 m','200 m')+range('sample','Hardware sampling rate',50,1000,10,'MHz','50 MHz','1000 MHz')+range('noise','Environment / clock noise',0,5,.1,'m','0 m','5 m')+measureButton;
  if(state.mode==='pbr')return range('distance','True distance',5,180,1,'m','5 m','180 m')+segment('channels','Measurement channels')+range('step','Frequency step Δf',1,20,1,'MHz','1 MHz','20 MHz')+range('phaseNoise','Phase noise',0,10,.5,'°','0 °','10 °')+pbrCandidateList()+measureButton;
  return range('distance','True distance',10,180,1,'m','10 m','180 m')+range('tofError','ToF coarse error',.5,15,.5,'m','0.5 m','15 m')+range('multipath','Multipath interference',0,100,1,'%','0 %','100 %')+segment('channels','PBR channels')+measureButton;
}
function pbrAmbiguityPeriod(){return state.channels===20?15:150/state.step}
function candidates(period){
  if(state.channels===20){
    const count=Math.max(1,Math.ceil(state.distance/period));
    const first=state.distance-(count-1)*period;
    return Array.from({length:count},(_,i)=>first+i*period);
  }
  if(state.channels===72&&state.distance<=150)return [state.distance];
  const arr=[];for(let v=state.distance%period;v<=200;v+=period)arr.push(v);return arr
}
function pbrVisual(){
  const count=state.channels===72?12:8;
  const channels=Array.from({length:count},(_,i)=>`<i style="--i:${i}"><b>f${i+1}</b></i>`).join('');
  return `<div class="pbr-visual-wrap"><div class="pbr-toolbar"><label class="rtt-toggle"><input type="checkbox" data-pbr-animation ${state.pbrAnimation?'checked':''}><span></span><em>Animation</em></label></div><div class="pbr-visual" aria-label="PBR phase-based ranging animation"><section class="pbr-panel"><h3>Channel Sweep</h3><div class="pbr-sweep">${channels}</div><p>CS samples multiple carrier frequencies. Each tone gives another phase observation.</p></section><section class="pbr-panel phase-panel"><h3>Phase Vector</h3><div class="phase-dial"><span class="phase-arm"></span><i></i></div><p>The measured I/Q vector rotates as the carrier frequency changes.</p></section><section class="pbr-panel"><h3>Phase Slope</h3><svg class="pbr-slope" viewBox="0 0 260 150" role="img" aria-label="Phase slope builds from multiple frequency points"><path class="pbr-slope-grid" d="M24 20v104M80 20v104M136 20v104M192 20v104M248 20v104M24 124h224M24 92h224M24 60h224M24 28h224"/><path class="pbr-slope-axis" d="M24 18v106h226"/><path class="pbr-slope-line" d="M38 110 L76 98 L114 82 L152 66 L190 48 L228 30"/><circle cx="38" cy="110" r="4"/><circle cx="76" cy="98" r="4"/><circle cx="114" cy="82" r="4"/><circle cx="152" cy="66" r="4"/><circle cx="190" cy="48" r="4"/><circle cx="228" cy="30" r="4"/></svg><p>Distance is estimated from the phase slope across frequency.</p></section></div></div>`;
}
function pbrCandidateList(){
  const period=pbrAmbiguityPeriod();
  const values=candidates(period);
  return `<div class="all-candidates"><div class="control-top"><label>All ambiguous candidates</label><output>${values.length} items</output></div><div class="candidate-list">${values.map(value=>`<span>${round(value)} m</span>`).join('')}</div></div>`;
}
function results(){if(state.mode==='tof'){const resolution=150/state.sample;const estimate=Math.round((state.distance+(Math.sin(state.distance*1.73)*state.noise))/resolution)*resolution;const err=estimate-state.distance;return `<div class="primary"><label>Estimated distance</label><strong>${round(estimate)}<small> m</small></strong><br><span class="pill">Error ${err>=0?'+':''}${round(err)} m</span></div><div class="metrics"><div class="metric"><span>Round-trip delay</span><b>${round(estimate*2/0.299792458)} ns</b></div><div class="metric"><span>Quantization resolution</span><b>${round(resolution)} m</b></div></div><div class="bar"><i style="width:${Math.min(100,estimate/2)}%"></i></div><div class="range-labels"><span>■ estimate □ true value</span></div>`}const period=pbrAmbiguityPeriod(),arr=candidates(period),best=arr.reduce((a,b)=>Math.abs(b-state.distance)<Math.abs(a-state.distance)?b:a);if(state.mode==='pbr'){const resolved=arr.length===1;return `<div class="control-top"><label>Distance candidate probability</label><output>${state.channels===72?'dense sweep':'sparse sweep'}</output></div><div class="candidate-track">${arr.map((v,i)=>`<i class="candidate" style="left:${v/2}%;height:${30+((i*17)%44)}px"></i>`).join('')}</div><div class="candidate-labels"><span>0 m</span><span>50</span><span>100</span><span>150</span><span>200 m</span></div><div class="metrics"><div class="metric"><span>Unambiguous distance</span><b>${round(period,1)} m</b></div><div class="metric"><span>Ambiguous candidates</span><b>${arr.length} items</b></div><div class="metric"><span>Selection state</span><b class="${resolved?'state-confirmed':'state-unknown'}">${resolved?'Confirmed':'Unknown'}</b></div></div>`}const tof=state.distance+state.tofError*.8+state.multipath/100*4,sparseFailure=state.channels===20&&state.multipath>=70&&state.tofError>=8&&arr.length>1,ghost=Math.min(200,state.distance+Math.min(12,Math.max(8,state.tofError*.7))),selected=sparseFailure?ghost:best,estimate=sparseFailure?ghost:selected+(state.multipath/100)*(state.channels===20?2.8:1.2),error=estimate-state.distance,failed=Math.abs(error)>2,shownCandidates=sparseFailure&&arr.every(v=>Math.abs(v-ghost)>.01)?arr.concat([ghost]):arr;return `<div class="metrics"><div class="metric"><span>1 · ToF boundary</span><b>${round(tof)} m</b><small>± ${round(state.tofError,1)} m</small></div><div class="metric"><span>2 · PBR candidates</span><b>${shownCandidates.length} items</b><small>${state.channels} channels · period ${round(period,1)} m</small></div><div class="metric"><span>3 · Fusion result</span><b>${round(estimate)} m</b><small>Error ${round(error)} m</small></div></div><div class="candidate-list">${shownCandidates.map(v=>`<span class="${Math.abs(v-selected)<.01?'best':''}">${round(v)} m</span>`).join('')}</div>${failed?`<p class="measurement-warning"><b>${sparseFailure?'Sparse-channel failure under harsh multipath':'Fusion error exceeds tolerance'}</b><span>${sparseFailure?'With only 20 sampled channels, poor channel quality can pull fusion toward a high-side ghost range near the ToF boundary. This illustrates why the Bluetooth SIG recommends a full 72-channel sweep: more frequency diversity gives the algorithm a stronger basis for rejecting ambiguous peaks.':`The fusion error is ${round(Math.abs(error))} m, which is above the 2 m pass threshold.`}</span></p>`:`<p class="success">${state.channels===72?'72-channel sweep maintains the correct fusion lock':'Fusion result is within 2 m tolerance'}</p>`}`}
function triggerRttAnimation(){
  const visual=$('.rtt-visual');
  if(!visual)return;
  visual.classList.remove('rtt-running');
  void visual.offsetWidth;
  visual.classList.add('rtt-running');
}
function bindRttAnimationToggle(){
  const toggle=$('[data-rtt-animation]');
  if(!toggle)return;
  toggle.addEventListener('change',e=>{
    state.rttAnimation=e.target.checked;
    $('.rtt-visual')?.classList.remove('rtt-running');
    if(state.rttAnimation)requestAnimationFrame(triggerRttAnimation);
  });
}
function bindPbrAnimationToggle(){
  const toggle=$('[data-pbr-animation]');
  if(!toggle)return;
  toggle.addEventListener('change',e=>{
    state.pbrAnimation=e.target.checked;
    $('.pbr-visual')?.classList.remove('pbr-running');
    $('#results')?.classList.remove('pbr-results-running');
    if(state.pbrAnimation)requestAnimationFrame(triggerPbrAnimation);
  });
}
function triggerPbrAnimation(){
  const visual=$('.pbr-visual');
  if(!visual)return;
  visual.classList.remove('pbr-running');
  void visual.offsetWidth;
  visual.classList.add('pbr-running');
}
function csFlowSeq(el){return Number(el.style.getPropertyValue('--seq')||0)}
function csFlowItems(){return Array.from(document.querySelectorAll('.csflow-visual-wrap .gantt-block,.csflow-visual-wrap .gantt-summary div'))}
function applyCsFlowStep(){
  const visual=$('.csflow-visual-wrap');
  if(!visual)return;
  visual.classList.toggle('csflow-manual',state.csFlowAnimation);
  csFlowItems().forEach(el=>{
    el.classList.toggle('flow-lit',state.csFlowAnimation&&csFlowSeq(el)<=state.csFlowStep);
  });
}
function resetCsFlowAnimation(){
  state.csFlowStep=-1;
  applyCsFlowStep();
}
function advanceCsFlowAnimation(){
  if(!state.csFlowAnimation)return;
  const maxSeq=Math.max(...csFlowItems().map(csFlowSeq),0);
  state.csFlowStep=state.csFlowStep>=maxSeq?-1:state.csFlowStep+1;
  applyCsFlowStep();
}
function bindCsFlowAnimationToggle(){
  const toggle=$('[data-csflow-animation]');
  const visual=$('.csflow-visual-wrap');
  if(!toggle||!visual)return;
  toggle.addEventListener('change',e=>{
    state.csFlowAnimation=e.target.checked;
    resetCsFlowAnimation();
  });
  visual.addEventListener('click',e=>{
    if(e.button!==0||e.target.closest('.rtt-toggle'))return;
    advanceCsFlowAnimation();
  });
  resetCsFlowAnimation();
}
function runMeasurement(){
  const button=$('.measure');
  if(!button)return;
  button.disabled=true;
  button.textContent='● Measuring…';
  button.classList.add('measuring');
  $('#results')?.classList.remove('pbr-results-running');
  if(state.mode==='tof'&&state.rttAnimation)triggerRttAnimation();
  if(state.mode==='pbr'&&state.pbrAnimation)triggerPbrAnimation();
  setTimeout(()=>{
    const original={distance:state.distance,noise:state.noise,phaseNoise:state.phaseNoise,tofError:state.tofError,multipath:state.multipath};
    let pbrMisread=false;
    let pbrMeasuredDistance=null;
    if(state.mode==='tof'){
      state.noise=(Math.random()*2-1)*original.noise;
    }else if(state.mode==='pbr'){
      const errorProbability=Math.max(0,(original.phaseNoise-3)/7)*.9;
      pbrMisread=Math.random()<errorProbability;
      if(pbrMisread){
        const period=pbrAmbiguityPeriod();
        const direction=original.distance+period<=180?1:-1;
        state.distance=Math.max(5,Math.min(180,original.distance+direction*period));
      }
      const period=pbrAmbiguityPeriod();
      const measuredCandidates=candidates(period);
      const selected=measuredCandidates.reduce((a,b)=>Math.abs(b-state.distance)<Math.abs(a-state.distance)?b:a);
      pbrMeasuredDistance=selected+Math.sin(state.distance)*state.phaseNoise/12;
    }
    $('#results').innerHTML=results();
	    if(state.mode==='pbr'){
	      const candidateBlock=$('.all-candidates');
	      if(candidateBlock)candidateBlock.outerHTML=pbrCandidateList();
	      if(state.pbrAnimation)$('#results')?.classList.add('pbr-results-running');
	    }
    Object.assign(state,original);
    const result=$('#results');
    result.classList.remove('result-flash');
    void result.offsetWidth;
    result.classList.add('result-flash');
    button.disabled=false;
    button.textContent='▶ Run another measurement';
    button.classList.remove('measuring');
	  },state.mode==='tof'&&state.rttAnimation?1900:state.mode==='pbr'&&state.pbrAnimation?1600:280);
}
function bind(){document.querySelectorAll('input[type=range]').forEach(el=>el.addEventListener('input',e=>{state[e.target.dataset.key]=Number(e.target.value);renderDynamic()}));document.querySelectorAll('[data-segment]').forEach(el=>el.addEventListener('click',e=>{state[e.target.dataset.segment]=Number(e.target.dataset.value);if(e.target.dataset.segment==='channels')state.step=state.channels===72?1:15;render()}));bindRttAnimationToggle();bindPbrAnimationToggle();$('.measure')?.addEventListener('click',runMeasurement)}
function closeRfZoom(){
  document.querySelector('.rf-zoom')?.remove();
  document.removeEventListener('keydown',handleRfZoomKey);
}
function handleRfZoomKey(e){
  if(e.key==='Escape')closeRfZoom();
}
function openRfZoom(plot){
  closeRfZoom();
  const title=plot.closest('.rf-panel')?.querySelector('h3')?.textContent||'RF Waveform';
  const clone=plot.cloneNode(true);
  clone.removeAttribute('id');
  clone.setAttribute('aria-label',`${title} enlarged view`);
  const overlay=document.createElement('div');
  overlay.className='rf-zoom';
  overlay.innerHTML=`<div class="rf-zoom-card" role="dialog" aria-modal="true" aria-label="${title} enlarged view"><div class="rf-zoom-head"><b>${title}</b><button class="rf-zoom-close" type="button" aria-label="Close enlarged view">×</button></div><div class="rf-zoom-body"></div></div>`;
  overlay.querySelector('.rf-zoom-body').appendChild(clone);
  overlay.addEventListener('click',e=>{if(e.target===overlay)closeRfZoom()});
  overlay.querySelector('.rf-zoom-close').addEventListener('click',closeRfZoom);
  document.body.appendChild(overlay);
  document.addEventListener('keydown',handleRfZoomKey);
}
function bindRfWaveformZoom(){
  document.querySelectorAll('.rf-waveform-grid .rf-plot').forEach(plot=>plot.addEventListener('click',()=>openRfZoom(plot)));
}
function shapeRfTimeDomainWaveform(){
  const panel=document.querySelector('.rf-waveform-grid .rf-panel:first-child');
  const trace=panel?.querySelector('.rf-trace');
  if(!panel||!trace)return;
  panel.querySelector('h3').textContent='Time Domain Waveform · Baseband';
  panel.querySelector('.rf-plot').setAttribute('aria-label','CS RF waveform showing a GFSK-modulated header followed by a CW sine tone');
  trace.setAttribute('d','M98 164 C102 149 107 149 112 164 C116 178 121 178 126 164 C132 145 137 145 143 164 C148 181 154 181 159 164 C164 151 168 151 173 164 C179 177 184 177 190 164 C196 146 202 146 208 164 C213 180 219 180 224 164 C229 146 234 146 239 164 C244 182 249 182 254 164 C259 146 264 146 269 164 C274 182 279 182 284 164 C289 146 294 146 299 164 C304 182 309 182 314 164 C319 146 324 146 329 164 C334 182 339 182 344 164 C349 146 354 146 359 164 C364 182 369 182 374 164 C377 154 380 154 382 164');
}
function vendorsVisual(){return `<div class="vendor-grid"><article class="vendor-card"><div class="vendor-head"><h3>Nordic Semiconductor</h3><span class="vendor-status ready">Development-ready / supported</span></div><p>The nRF54L Series supports Channel Sounding with a new radio. nRF Connect SDK 3.0.1 and later provide a qualified Host/Controller, Initiator and Reflector samples, and an open IFFT distance algorithm.</p><div class="vendor-products"><span>nRF54L Series</span><span>nRF54LM20A</span><span>nRF Connect SDK</span><span>nRF Toolbox</span></div><a href="https://www.nordicsemi.com/Products/Wireless/Bluetooth-Low-Energy/Channel-Sounding" target="_blank">Official Channel Sounding solution →</a></article><article class="vendor-card"><div class="vendor-head"><h3>Silicon Labs</h3><span class="vendor-status ready">Available / complete kit</span></div><p>Silicon Labs provides Channel Sounding radio support, a Bluetooth 6.0 stack, RTL ranging library, visualization tools, and single-/dual-antenna development platforms based on EFR32xG24 / BG24L.</p><div class="vendor-products"><span>EFR32xG24</span><span>BG24L</span><span>xG24-DK2606A</span><span>xG24-PK6036A</span></div><a href="https://www.silabs.com/wireless/bluetooth/channel-sounding" target="_blank">Official Channel Sounding solution →</a></article><article class="vendor-card"><div class="vendor-head"><h3>Qualcomm</h3><span class="vendor-status platform">Platform integration</span></div><p>Channel Sounding is integrated into mobile and connectivity platforms for phones, earbuds, computing, and XR proximity. Public platforms include FastConnect 7700 and newer Snapdragon platforms with Bluetooth 6.0.</p><div class="vendor-products"><span>FastConnect 7700</span><span>Snapdragon 6 Gen 5</span><span>Snapdragon 8 Elite Gen 5</span></div><a href="https://www.qualcomm.com/smartphones/products/6-series/snapdragon-6-gen-5-mobile-platform" target="_blank">Official platform information →</a></article><article class="vendor-card"><div class="vendor-head"><h3>Texas Instruments</h3><span class="vendor-status ready">Development-ready / complete SDK</span></div><p>SimpleLink CC27xx wireless MCUs include an Algorithm Processing Unit and provide a Channel Sounding stack, BLECSRanging library, IFFT/MUSIC post-processing methods, and LaunchPad examples.</p><div class="vendor-products"><span>CC27xx</span><span>CC2745R10-Q1</span><span>Low Power F3 SDK</span><span>BLECSRanging</span></div><a href="https://www.ti.com/video/6363699718112" target="_blank">Official Channel Sounding introduction →</a></article><article class="vendor-card"><div class="vendor-head"><h3>NXP Semiconductors</h3><span class="vendor-status ready">Certified / automotive and IoT</span></div><p>KW47 and MCX W72 are Channel Sounding-certified wireless MCUs with an on-chip localization compute engine, MCUXpresso SDK, and a dual-antenna Localization Board.</p><div class="vendor-products"><span>KW47</span><span>MCX W72</span><span>MCXW72-LOC</span><span>MCUXpresso SDK</span></div><a href="https://www.nxp.com/products/wireless-connectivity/bluetooth-channel-sounding:BLUETOOTH-CHANNEL-SOUNDING" target="_blank">Official Channel Sounding solution →</a></article><article class="vendor-card"><div class="vendor-head"><h3>Realtek</h3><span class="vendor-status roadmap">Technology roadmap</span></div><p>Realtek’s 2025 annual report lists channel sounding in its 2026 spatial sensing roadmap, but no publicly verifiable Bluetooth Channel Sounding development solution or model has been found yet.</p><div class="vendor-products"><span>2026 roadmap</span><span>Model pending official announcement</span></div><a href="https://www.realtek.com/images/ar/2025_Annual_Report__1.pdf" target="_blank">Official annual report →</a></article><article class="vendor-card"><div class="vendor-head"><h3>MediaTek</h3><span class="vendor-status">Not publicly confirmed</span></div><p>MediaTek has launched mobile platforms with Bluetooth 6.0 support, but no official product page was found that explicitly announces a Bluetooth Channel Sounding solution, development kit, or distance algorithm.</p><div class="vendor-products"><span>Bluetooth 6.0 platforms</span><span>CS support pending confirmation</span></div></article></div><div class="vendor-summary"><b>Adoption path</b><p>For IoT or tag prototypes, start by evaluating Nordic, Silicon Labs, TI, or NXP. For phones and highly integrated connectivity platforms, monitor Qualcomm. MediaTek and Realtek should be verified through actual chip datasheets, Bluetooth Qualification records, and vendor FAE responses; Bluetooth 6.0 alone does not imply Channel Sounding support.</p></div><p class="source-note">Status is based on official public information as of 2026-07-12; supply, qualification versions, and regional availability may change.</p>`}
function vendorsVisualWithAiroha(){
  const airohaCard=`<article class="vendor-card"><div class="vendor-head"><h3>Airoha Technology</h3><span class="vendor-status platform">Bluetooth 6.0 / CS pending confirmation</span></div><p>Airoha has launched the AB1595, a 12 nm six-core Bluetooth 6.0 flagship audio SoC with built-in AI hardware acceleration for premium earbuds, XR, spatial audio, and low-latency multichannel applications. The product launched in Q1 2025.</p><p>Current public official information does not explicitly list PBR/RTT, Initiator/Reflector roles, Ranging Profile, or distance algorithms, so Bluetooth 6.0 alone should not be treated as proof of Channel Sounding support.</p><div class="vendor-products"><span>AB1595</span><span>12 nm/6-core</span><span>Bluetooth 6.0</span><span>CS support pending official confirmation</span></div><a href="https://www.airoha.com/zh-TW/about/responsibility/technology" target="_blank">Airoha official products and technology →</a></article>`;
  return vendorsVisual().replace('</div><div class="vendor-summary">',`${airohaCard}</div><div class="vendor-summary">`);
}
function usecasesVisual(){return `<div class="usecase-grid"><article class="usecase-card featured"><span class="usecase-icon">01</span><h3>Security, access control, and smart locks</h3><p>Traditional access control can only verify credentials, while RSSI can be misled by blockage or power manipulation. Channel Sounding can confirm whether an authorized device is actually outside the door or within a defined secure zone.</p><div class="usecase-flow"><span>Phone / badge</span><i>→</i><span>Secure ranging</span><i>→</i><span>Lock decision</span></div><div class="usecase-benefits"><span>Relay-attack resistance</span><span>Inside/outside discrimination</span><span>Touchless access</span><span>Trusted proximity</span></div></article><article class="usecase-card featured"><span class="usecase-icon">02</span><h3>Logistics warehousing and RFID collaboration</h3><p>RFID is well suited to low-cost mass identification and inventory, while Channel Sounding provides more precise real-time distance for high-value assets, vehicles, or personnel. The two can be layered rather than treated as replacements.</p><div class="usecase-flow"><span>RFID inventory</span><i>→</i><span>BLE identity connection</span><i>→</i><span>CS precision ranging</span></div><div class="usecase-benefits"><span>High-value asset tracking</span><span>Shelf-zone confirmation</span><span>Forklift collision avoidance</span><span>Misplaced-goods alerts</span></div></article><article class="usecase-card"><span class="usecase-icon">03</span><h3>Automotive electronics and Digital Key</h3><p>A vehicle uses multiple Bluetooth anchors to determine the phone or key position, confirm approach direction, distance, and inside/outside zones, then trigger welcome, unlock, start, or cabin personalization flows.</p><div class="usecase-flow"><span>Phone / Key Fob</span><i>→</i><span>Multi-anchor ranging</span><i>→</i><span>PEPS / PaaK</span></div><div class="usecase-benefits"><span>Passive entry/start</span><span>Relay-attack resistance</span><span>Inside/outside detection</span><span>Cabin personalization</span></div></article><article class="usecase-card"><span class="usecase-icon">04</span><h3>Find My and consumer asset tracking</h3><p>At long range, a broad Bluetooth finding network provides location. Near the item, Channel Sounding gives a more stable precise distance than RSSI to guide users to earbuds, remotes, or tags.</p><div class="usecase-flow"><span>Cloud location</span><i>→</i><span>BLE proximity</span><i>→</i><span>CS precision find</span></div><div class="usecase-benefits"><span>Close-range precision finding</span><span>Low-power tag</span><span>Single-antenna capable</span><span>Phone ecosystem integration</span></div></article><article class="usecase-card"><span class="usecase-icon">05</span><h3>Industrial safety and human-machine collaboration</h3><p>Worker badges, tools, AGVs, robotic arms, and hazardous equipment continuously measure distance and adjust speed, stop, or alert based on safety zones.</p><div class="usecase-flow"><span>Worker / AGV</span><i>→</i><span>Distance zone</span><i>→</i><span>PLC / Safety action</span></div><div class="usecase-benefits"><span>Human-vehicle collision avoidance</span><span>Electronic geofencing</span><span>Tool authorization</span><span>Dynamic safety zones</span></div></article><article class="usecase-card"><span class="usecase-icon">06</span><h3>Healthcare, care, and smart spaces</h3><p>Locate medical equipment, beds, and staff, or control lighting, displays, and environmental systems based on user distance to reduce search time and improve spatial automation.</p><div class="usecase-flow"><span>Connected asset</span><i>→</i><span>Secure ranging</span><i>→</i><span>Location service</span></div><div class="usecase-benefits"><span>Equipment finding</span><span>Zone authorization</span><span>Staff dispatch</span><span>Context automation</span></div></article></div><section class="rfid-stack"><h3>Hybrid warehouse architecture: RFID + Bluetooth + Channel Sounding</h3><div class="rfid-stack-grid"><div><b>RFID Layer</b><span>Mass, low-cost identity recognition and batch inventory</span></div><div><b>Bluetooth Layer</b><span>Low-power connectivity, beacons, and device management</span></div><div><b>CS Ranging Layer</b><span>Secure precision ranging for critical objects</span></div><div><b>WMS / RTLS</b><span>Fuse location, inventory, and workflow decisions</span></div></div></section><p class="source-note">Channel Sounding provides raw ranging data and standardized procedures; actual positioning, zone decisions, and safety control still require multiple anchors, maps, sensor fusion, and application algorithms.</p>`}
function conclusionVisual(){return `<div class="conclusion-grid"><section class="conclusion-panel future"><h3>OPPORTUNITIES</h3><div class="conclusion-item"><b>01</b><div><strong>Native distance awareness for Bluetooth devices</strong><p>Phones, earbuds, tags, smart locks, and IoT nodes can gain precise distance capability without adding a separate UWB radio.</p></div></div><div class="conclusion-item"><b>02</b><div><strong>Digital keys and secure access control</strong><p>PBR precision combined with RTT distance bounding can improve inside/outside decisions and reduce relay-attack risk.</p></div></div><div class="conclusion-item"><b>03</b><div><strong>Find My and asset tracking upgrades</strong><p>Bluetooth finding networks can provide broad discovery, while Channel Sounding enables precision finding at close range.</p></div></div><div class="conclusion-item"><b>04</b><div><strong>Hybrid positioning across industries</strong><p>RFID, Wi-Fi, GNSS, IMU, AoA, and maps can be fused with CS to improve warehouse, automotive, healthcare, and industrial workflows.</p></div></div><div class="conclusion-item"><b>05</b><div><strong>Algorithm and service value chain</strong><p>The specification standardizes measurement data, while vendors can differentiate through multipath mitigation, localization fusion, and cloud services.</p></div></div></section><section class="conclusion-panel"><h3>CHALLENGES</h3><div class="conclusion-item"><b>01</b><div><strong>NLoS and multipath error</strong><p>Metal, walls, and human blockage can distort phase and bias distance estimates, requiring antenna diversity and robust quality metrics.</p></div></div><div class="conclusion-item"><b>02</b><div><strong>Phase calibration and hardware variation</strong><p>LO offset, RF path delay, PCB layout, antennas, and temperature drift all require calibration and compensation.</p></div></div><div class="conclusion-item"><b>03</b><div><strong>Distance algorithms are not unified</strong><p>Bluetooth defines the measurement procedure, not one mandatory ranging algorithm, so accuracy and confidence may differ by vendor.</p></div></div><div class="conclusion-item"><b>04</b><div><strong>Power, latency, and scalability</strong><p>More channels, antenna paths, and repeated measurements improve accuracy but increase airtime, computation, power, and scheduling load.</p></div></div><div class="conclusion-item"><b>05</b><div><strong>Interoperability and terminal adoption</strong><p>Phones, tags, vehicles, and IoT chips need compatible roles, profiles, data formats, and security policies.</p></div></div><div class="conclusion-item"><b>06</b><div><strong>Security and privacy need system design</strong><p>Secure ranging does not replace authentication, key management, anti-replay design, authorization, or location privacy protection.</p></div></div></section></div><section class="outlook-roadmap"><h3>Possible Industry Path</h3><div class="roadmap-line"><div class="roadmap-stage active"><b>Near Term · Enablement</b><span>Chips, SDKs, development boards, phone interoperability, and reference algorithms mature quickly.</span></div><div class="roadmap-stage"><b>Mid Term · Deployment</b><span>Digital keys, Find My, smart locks, and industrial tags move into larger deployments.</span></div><div class="roadmap-stage"><b>Long Term · Spatial IoT</b><span>CS fuses with RFID, Wi-Fi, UWB, and sensors so devices can cooperate through trusted spatial relationships.</span></div></div></section><div class="final-statement"><b>FINAL TAKEAWAY</b><p>Channel Sounding is important not only because it moves Bluetooth ranging from meter-level proximity toward centimeter-level precision, but because it gives the low-power Bluetooth ecosystem a standardized, interoperable, and security-aware distance layer.</p></div>`}
function renderDynamic(){
  document.querySelectorAll('input[type=range]').forEach(el=>{
    const out=$(`#${el.dataset.key}-out`);
    const units={distance:'m',sample:'MHz',noise:'m',step:'MHz',phaseNoise:'°',tofError:'m',multipath:'%'};
    out.textContent=`${state[el.dataset.key]} ${units[el.dataset.key]}`;
  });
  $('#concept-visual').innerHTML=visual();
  bindRttAnimationToggle();
  bindPbrAnimationToggle();
  if(state.mode==='pbr'){
    const candidateBlock=$('.all-candidates');
    if(candidateBlock)candidateBlock.outerHTML=pbrCandidateList();
  }
  $('#results').innerHTML=results();
}
function marketVisual(){return `<div class="market-kpis"><article class="market-kpi"><span>2025 global market value</span><strong>US$31.26B</strong><small>Indoor positioning and navigation</small></article><article class="market-kpi"><span>2030 projected value</span><strong>US$136.29B</strong><small>2025-2030 CAGR 34.24%</small></article><article class="market-kpi"><span>BLE 2024 share</span><strong>33.76%</strong><small>Largest single technology category</small></article></div><div class="market-grid"><section class="market-panel"><h3>2024 Technology Share</h3><div class="share-row"><span>Bluetooth LE</span><div class="share-track"><i class="share-fill ble" style="width:33.76%"></i></div><output>33.76%</output></div><div class="share-row"><span>Wi-Fi positioning</span><div class="share-track"><i class="share-fill" style="width:26%"></i></div><output>~26%</output></div><div class="share-row"><span>UWB</span><div class="share-track"><i class="share-fill" style="width:18%"></i></div><output>~18%</output></div><div class="share-row"><span>RFID / other</span><div class="share-track"><i class="share-fill" style="width:22.24%"></i></div><output>~22%</output></div><p class="source-note">BLE share is based on public reports; other splits are illustrative estimates.</p></section><section class="market-panel"><h3>Market Value Growth</h3><div class="value-bars"><div class="value-column"><i style="height:46px"></i><b>US$31.26B</b><span>2025</span></div><div class="value-column"><i style="height:200px"></i><b>US$136.29B</b><span>2030</span></div></div></section></div><div class="market-cs"><b>CHANNEL SOUNDING · Incremental Market</b><p>Channel Sounding is introduced with Bluetooth 6.0 and is usually counted inside BLE in public market reports. Its value is in upgrading broad BLE proximity use cases into secure precision ranging.</p></div><p class="source-note">Market scope: global indoor positioning and navigation. Sources: <a href="https://www.mordorintelligence.com/industry-reports/indoor-positioning-and-navigation-market" target="_blank">Mordor Intelligence</a>, <a href="https://www.bluetooth.com/2025-market-update/" target="_blank">Bluetooth Market Update 2025</a>, <a href="https://www.firaconsortium.org/node/728" target="_blank">FiRa UWB Market Outlook</a>.</p>`}
function csIntroVisual(){return `<div class="cs-overview-grid"><article class="cs-overview-card"><span class="num">01 · SYSTEM ROLES</span><h3>Initiator and Reflector</h3><p>Channel Sounding runs between two connected devices in a 1:1 topology. The Initiator starts the procedure and estimates distance; the Reflector responds with packets or tones.</p></article><article class="cs-overview-card"><span class="num">02 · PHYSICAL CHANNEL</span><h3>2.4 GHz Multichannel Measurement</h3><p>CS collects phase and timing data across multiple 1 MHz-spaced ranging channels. Up to 72 ranging channels can reduce single-frequency fading and reflection bias.</p></article><article class="cs-overview-card"><span class="num">03 · PBR</span><h3>Phase-Based Ranging</h3><p>Initiator and Reflector exchange tones at different carrier frequencies. Distance maps to phase slope versus frequency, enabling fine resolution while requiring 2π ambiguity handling.</p></article><article class="cs-overview-card"><span class="num">04 · RTT</span><h3>Round-Trip Timing</h3><p>Encrypted packet round-trip timing provides an unambiguous coarse distance and a secure distance-bounding reference.</p></article><article class="cs-overview-card wide"><span class="num">05 · PROCEDURE FLOW</span><h3>A Channel Sounding Procedure</h3><div class="cs-flow"><div><b>ACL Connection</b><span>Connect and exchange capabilities</span></div><i>→</i><div><b>CS Sub-events</b><span>Run RTT / PBR steps across channels</span></div><i>→</i><div><b>Distance Algorithm</b><span>Fuse phase, timing, and quality metrics</span></div></div><div class="cs-specs"><div class="cs-spec"><b>±20 cm</b><span>Early implementation accuracy</span></div><div class="cs-spec"><b>Up to 150 m</b><span>Range under favorable conditions</span></div><div class="cs-spec"><b>72 channels</b><span>Available ranging frequencies</span></div><div class="cs-spec"><b>Up to 4</b><span>Supported antenna paths</span></div></div></article><article class="cs-overview-card"><span class="num">06 · SECURITY</span><h3>Layered Security</h3><p>RTT distance bounding, randomized measurement sequences, encrypted content, quality metrics, and attack detection support trusted distance applications.</p></article><article class="cs-overview-card"><span class="num">07 · APPLICATIONS</span><h3>Main Applications</h3><p>Digital keys, smart locks, Find My, indoor navigation, industrial asset tracking, worker safety, and proximity automation.</p></article></div><p class="source-note">Capabilities are based on Bluetooth Core 6.0 public material. Real accuracy and range depend on chip, antenna, power, environment, and algorithm.</p>`}
function csWaveformVisual(){return `<div class="rf-waveform-grid"><section class="rf-panel"><h3>Time Domain Envelope · Baseband</h3><svg class="rf-plot" viewBox="0 0 760 360" role="img" aria-label="CS RF waveform envelope showing GFSK header followed by CW tone"><rect x="58" y="34" width="650" height="260" fill="#0b1117"/><rect class="rf-header-zone" x="98" y="34" width="126" height="260"/><rect class="rf-tone-zone" x="224" y="34" width="158" height="260"/><g class="rf-grid"><path d="M176 34v260M254 34v260M332 34v260M410 34v260M488 34v260M566 34v260M644 34v260M58 99h650M58 164h650M58 229h650"/></g><path class="rf-slot" d="M98 28v272M626 28v272"/><path class="rf-axis" d="M58 34v260h650"/><path class="rf-trace" d="M98 164 L104 160 L110 167 L116 162 L122 165 L128 160 L134 166 L140 161 L146 164 L152 160 L158 166 L164 163 L170 165 L176 161 L182 166 L188 162 L194 164 L200 160 L206 165 L212 162 L218 166 L224 164 L230 162 L236 165 L242 163 L248 164 L254 162 L260 166 L266 160 L272 165 L278 162 L284 164 L290 161 L296 166 L302 163 L308 165 L314 161 L320 164 L326 162 L332 166 L338 163 L344 165 L350 161 L356 164 L362 162 L368 166 L374 163 L382 164"/><text class="rf-label" x="106" y="58">Slot 0</text><text class="rf-label header" x="112" y="138">GFSK Header</text><text class="rf-label tone" x="250" y="138">CS CW Tone</text><text class="rf-tick" x="30" y="299">0.0</text><text class="rf-tick" x="24" y="168">1.0</text><text class="rf-tick" x="24" y="42">2.0</text><text class="rf-tick" x="94" y="318">0</text><text class="rf-tick" x="170" y="318">100</text><text class="rf-tick" x="248" y="318">200</text><text class="rf-tick" x="326" y="318">300</text><text class="rf-tick" x="404" y="318">400</text><text class="rf-tick" x="482" y="318">500</text><text class="rf-tick" x="560" y="318">600</text><text class="rf-tick" x="638" y="318">700</text><text class="rf-label" x="340" y="346">Time (us)</text><text class="rf-label" transform="translate(24 195) rotate(-90)">Amplitude</text></svg></section><section class="rf-panel"><h3>CS Tone Phase Vector</h3><svg class="rf-plot" viewBox="0 0 430 430" role="img" aria-label="CS tone phase vector on I and Q plane"><rect x="52" y="38" width="330" height="330" fill="#0b1117"/><g class="rf-grid"><path d="M107 38v330M162 38v330M272 38v330M327 38v330M52 93h330M52 148h330M52 258h330M52 313h330"/></g><path class="phase-cross" d="M217 38v330M52 203h330"/><circle class="phase-ring" cx="217" cy="203" r="110"/><circle class="phase-dot" cx="315" cy="152" r="9"/><circle class="phase-dot" cx="320" cy="154" r="8"/><circle class="phase-dot" cx="316" cy="158" r="8"/><circle class="phase-dot" cx="312" cy="155" r="7"/><path class="rf-axis" d="M52 38v330h330"/><text class="rf-tick" x="34" y="372">-1.5</text><text class="rf-tick" x="209" y="386">0.0</text><text class="rf-tick" x="372" y="386">1.5</text><text class="rf-tick" x="17" y="207">0.0</text><text class="rf-tick" x="24" y="46">1.5</text><text class="rf-label tone" x="165" y="26">d = 5.0 m</text></svg></section><section class="rf-panel"><h3>Power Spectral Density · PSD</h3><svg class="rf-plot" viewBox="0 0 980 320" role="img" aria-label="Power spectral density with a central CW tone peak"><rect x="64" y="34" width="860" height="220" fill="#0b1117"/><g class="rf-grid"><path d="M207 34v220M350 34v220M494 34v220M637 34v220M780 34v220M64 70h860M64 107h860M64 144h860M64 181h860M64 217h860"/></g><path class="rf-axis" d="M64 34v220h860"/><path class="rf-spectrum-fill" d="M64 254 L64 198 L82 209 L100 216 L118 211 L136 214 L154 207 L172 211 L190 208 L207 203 L225 206 L243 200 L261 202 L279 198 L297 197 L315 193 L333 188 L350 184 L368 178 L386 170 L404 160 L422 149 L440 137 L458 119 L476 90 L488 66 L494 38 L500 67 L512 91 L530 119 L548 138 L566 151 L584 163 L602 171 L619 178 L637 185 L655 190 L673 195 L691 198 L709 202 L727 205 L745 207 L762 210 L780 212 L798 209 L816 213 L834 211 L852 216 L870 212 L888 218 L906 215 L924 219 L924 254 Z"/><path class="rf-spectrum-line" d="M64 198 L82 209 L100 216 L118 211 L136 214 L154 207 L172 211 L190 208 L207 203 L225 206 L243 200 L261 202 L279 198 L297 197 L315 193 L333 188 L350 184 L368 178 L386 170 L404 160 L422 149 L440 137 L458 119 L476 90 L488 66 L494 38 L500 67 L512 91 L530 119 L548 138 L566 151 L584 163 L602 171 L619 178 L637 185 L655 190 L673 195 L691 198 L709 202 L727 205 L745 207 L762 210 L780 212 L798 209 L816 213 L834 211 L852 216 L870 212 L888 218 L906 215 L924 219"/><path class="rf-slot" d="M494 34v220"/><text class="rf-tick" x="48" y="74">0</text><text class="rf-tick" x="36" y="111">-10</text><text class="rf-tick" x="36" y="148">-20</text><text class="rf-tick" x="36" y="185">-30</text><text class="rf-tick" x="36" y="221">-40</text><text class="rf-tick" x="36" y="258">-50</text><text class="rf-tick" x="57" y="274">-3</text><text class="rf-tick" x="200" y="274">-2</text><text class="rf-tick" x="343" y="274">-1</text><text class="rf-tick" x="491" y="274">0</text><text class="rf-tick" x="634" y="274">1</text><text class="rf-tick" x="777" y="274">2</text><text class="rf-tick" x="919" y="274">3</text><text class="rf-label" x="425" y="304">Frequency Offset (MHz)</text><text class="rf-label" transform="translate(25 185) rotate(-90)">Relative Power (dB)</text></svg></section></div><div class="rf-notes"><div class="rf-note important"><b>GFSK Header</b><span>The first portion of the CS waveform remains a GFSK packet header for synchronization, packet identification, and control information; it is not the tone used for direct phase reading.</span></div><div class="rf-note"><b>CW Tone</b><span>The second portion switches to a continuous-wave tone, allowing the receiving side to measure phase on a stable carrier. This is the core input for PBR distance estimation.</span></div><div class="rf-note"><b>PSD View</b><span>The PSD view shows the CW tone forming a main peak at the center frequency offset, with lower-power spectral skirts and the noise floor on both sides.</span></div></div><p class="source-note">This page redraws the attached waveform concept using the presentation's cyan/lime dark theme. Timing, spectrum, and phase points are illustrative and do not represent fixed specification parameters.</p>`}
function csCompareVisual(){return `<div class="tech-table-wrap"><table class="tech-table"><thead><tr><th>Comparison Item</th><th class="cs-col">Bluetooth LE<br>Channel Sounding</th><th>Bluetooth Classic<br>BR</th><th>Bluetooth Classic<br>EDR</th></tr></thead><tbody><tr><th>Modulation</th><td class="cs-col">GFSK packet header + CS tone<br>RTT uses packets; PBR uses CW tone phase</td><td>GFSK<br>Frequency deviation carries data bits</td><td>GFSK access code / header + PSK payload<br>π/4-DQPSK or 8DPSK</td></tr><tr><th>Data Rate</th><td class="cs-col">Not a conventional data-throughput PHY<br>Measurements run according to the LE connection schedule</td><td>1 Msym/s<br>Approx. 1 Mb/s gross rate</td><td>2 Mb/s gross rate (π/4-DQPSK)<br>3 Mb/s gross rate (8DPSK)</td></tr><tr><th>Payload</th><td class="cs-col">Ranging fields, timestamp, phase, and quality data<br>The CS tone does not carry application payload</td><td>Classic ACL / SCO packet data<br>Control, voice, and low-to-medium data rate use</td><td>Higher-efficiency ACL payload<br>Audio streaming and higher-throughput Classic Bluetooth use</td></tr><tr><th>Application Area</th><td class="cs-col">Secure precision ranging, digital keys, smart locks, Find My, RTLS, industrial asset tracking</td><td>Classic device links, HID, serial-port profile, voice, and legacy accessories</td><td>Wireless audio, vehicle infotainment, earbuds, speakers, and higher-data-rate Classic applications</td></tr></tbody></table></div><div class="tech-notes"><div class="tech-note"><b>CS Focus</b><span>Produces trusted ranging measurements, not application throughput.</span></div><div class="tech-note"><b>BR Focus</b><span>Provides the basic Classic Bluetooth data link.</span></div><div class="tech-note"><b>EDR Focus</b><span>Uses PSK payload modulation to raise Classic Bluetooth data rate.</span></div><div class="tech-note"><b>Design Difference</b><span>BR/EDR is a data plane; CS is closer to a ranging measurement plane.</span></div></div><p class="source-note">This is a conceptual briefing comparison. Actual packet format, payload size, and data rate depend on packet type, slot count, coding, controller implementation, and protocol layer.</p>`}
function csFlowVisual(){return `<div class="csflow-visual-wrap"><div class="pbr-toolbar"><label class="rtt-toggle"><input type="checkbox" data-csflow-animation ${state.csFlowAnimation?'checked':''}><span></span><em>Animation</em></label></div><div class="gantt-wrap csflow-visual"><div class="gantt"><div class="gantt-axis"><span>LANE / TIME</span><span>0</span><span>200 μs</span><span>400 μs</span><span>600 μs</span><span>800 μs</span><span>1000 μs</span></div><div class="gantt-row"><div class="gantt-label">ACL / Link Layer</div><div class="gantt-track"><span class="gantt-block" style="left:1%;width:17%;--seq:0">Capability exchange</span><span class="gantt-block" style="left:19%;width:16%;--seq:1">CS setup</span><span class="gantt-block process" style="left:87%;width:12%;--seq:13">Report</span></div></div><div class="gantt-row"><div class="gantt-label">Initiator TX</div><div class="gantt-track"><span class="gantt-block rtt" style="left:36%;width:9%;--seq:2">RTT packet</span><span class="gantt-block pbr" style="left:51%;width:8%;--seq:5">Tone f1</span><span class="gantt-block pbr" style="left:67%;width:8%;--seq:8">Tone f2</span></div></div><div class="gantt-row"><div class="gantt-label">Reflector RX / Measure</div><div class="gantt-track"><span class="gantt-block rtt" style="left:38%;width:9%;--seq:3">RX + timestamp</span><span class="gantt-block pbr" style="left:53%;width:9%;--seq:6">Phase φ1</span><span class="gantt-block pbr" style="left:69%;width:9%;--seq:9">Phase φ2</span></div></div><div class="gantt-row"><div class="gantt-label">Reflector TX</div><div class="gantt-track"><span class="gantt-block rtt" style="left:47%;width:9%;--seq:4">RTT response</span><span class="gantt-block pbr" style="left:60%;width:8%;--seq:7">Tone return</span><span class="gantt-block pbr" style="left:76%;width:8%;--seq:10">Tone return</span></div></div><div class="gantt-row"><div class="gantt-label">Initiator RX / Measure</div><div class="gantt-track"><span class="gantt-block rtt" style="left:49%;width:9%;--seq:4">RTT Δt</span><span class="gantt-block pbr" style="left:62%;width:9%;--seq:7">Phase φ1'</span><span class="gantt-block pbr" style="left:78%;width:9%;--seq:10">Phase φ2'</span></div></div><div class="gantt-row"><div class="gantt-label">Distance Engine</div><div class="gantt-track"><span class="gantt-block process" style="left:58%;width:13%;--seq:11">RTT coarse range</span><span class="gantt-block process" style="left:72%;width:15%;--seq:12">PBR phase slope</span><span class="gantt-block process" style="left:88%;width:11%;--seq:14">Fusion output</span></div></div></div></div><div class="gantt-legend"><span><i style="border-color:#446471"></i>Connection / control</span><span><i style="border-color:#b0d765"></i>RTT secure distance</span><span><i style="border-color:#72e7fa"></i>PBR high-precision phase</span><span><i style="border-color:#9d7bd0"></i>Algorithm processing</span></div><div class="gantt-summary"><div style="--seq:0"><b>1 · Setup</b><span>Exchange capabilities and configure procedure</span></div><div style="--seq:4"><b>2 · RTT Steps</b><span>Encrypted packet round trip and timestamp</span></div><div style="--seq:8"><b>3 · PBR Steps</b><span>Multi-frequency tone round trip and phase measurement</span></div><div style="--seq:12"><b>4 · Fusion</b><span>Quality filtering, ambiguity resolution, and output</span></div></div><p class="source-note">This is a conceptual timing diagram, not a fixed microsecond schedule from the specification.</p></div>`}
function render(){const m=modes[state.mode];$('#mode-label').textContent=m.label;$('#mode-title').textContent=m.title;$('#mode-description').textContent=m.description;$('#mode-formula').textContent=m.formula;$('#formula-link').style.display=state.mode==='pbr'?'inline-block':'none';$('#lab-title').textContent=m.lab;$('#lab-description').textContent=m.labDesc;$('#concept-visual').innerHTML=state.mode==='tech'?techVisual():state.mode==='market'?marketVisual():state.mode==='csintro'?csIntroVisual():state.mode==='cswaveform'?csWaveformVisual():state.mode==='cscompare'?csCompareVisual():state.mode==='csflow'?csFlowVisual():state.mode==='usecases'?usecasesVisual():state.mode==='vendors'?vendorsVisualWithAiroha():state.mode==='conclusion'?conclusionVisual():visual();const featureHtml=state.mode==='tech'?`<small>SELECTION CRITERIA</small><h3>Accuracy is not the only criterion</h3><p>Real product selection must also consider installed-device penetration, power consumption, anchor deployment cost, NLoS environments, secure distance boundaries, and available spectrum.</p>`:state.mode==='market'?`<small>MARKET READING</small><h3>Channel Sounding expands the addressable market for precision ranging</h3><p>UWB focuses on very high precision; Bluetooth Channel Sounding uses the existing BLE ecosystem to bring centimeter-level distance capability to more devices at lower incremental cost.</p>`:state.mode==='csintro'?`<small>CORE IDEA</small><h3>Standardizes measurement data without constraining the ranging algorithm</h3><p>The Bluetooth specification defines how phase, timing, and quality information are securely collected; actual distance estimation and multipath processing are implemented by chip vendors or product developers.</p>`:state.mode==='cswaveform'?`<small>WAVEFORM READING</small><h3>CS is not converted into a tone for the entire packet</h3><p>The packet header still uses GFSK so the receiving side can complete synchronization and packet processing; only the later portion is the CW tone used for phase discrimination, and PBR mainly reads the phase of this stable carrier.</p>`:state.mode==='cscompare'?`<small>PHY POSITIONING</small><h3>BR/EDR is data transport; CS is ranging measurement</h3><p>BR/EDR carries application data or audio through packet payloads; Channel Sounding tones and measurement fields serve distance estimation, so data rate and payload should not be compared using conventional throughput assumptions.</p>`:state.mode==='csflow'?`<small>READING THE TIMELINE</small><h3>RTT and PBR can be arranged as different steps in the same procedure</h3><p>RTT provides coarse absolute distance and security checks; multi-frequency PBR steps provide fine phase information, and the ranging algorithm performs quality filtering, periodic ambiguity resolution, and fusion.</p>`:state.mode==='vendors'?`<small>VENDOR CHECKLIST</small><h3>Bluetooth 6.0 does not automatically mean Channel Sounding support</h3><p>When selecting a solution, verify the radio PHY, Bluetooth qualification, Initiator/Reflector roles, Ranging Profile, algorithm, antenna reference design, and SDK examples.</p>`:feature();$('#feature-card').innerHTML=featureHtml;$('#feature-card').style.display=featureHtml?'block':'none';const isStatic=['intro','overview','tech','market','csintro','cswaveform','cscompare','csflow','usecases','vendors','conclusion'].includes(state.mode);$('.lab-section').style.display=isStatic?'none':'block';if(!isStatic){$('#controls').innerHTML=controls();$('#results').innerHTML=results();bind();if(state.mode==='tof'&&state.rttAnimation)requestAnimationFrame(triggerRttAnimation);if(state.mode==='pbr'&&state.pbrAnimation)requestAnimationFrame(triggerPbrAnimation)}if(state.mode==='csflow')bindCsFlowAnimationToggle();if(state.mode==='cswaveform'){shapeRfTimeDomainWaveform();bindRfWaveformZoom()}document.querySelectorAll('.mode-tab').forEach(b=>b.classList.toggle('active',b.dataset.mode===state.mode))}
document.querySelectorAll('.mode-tab').forEach(b=>b.addEventListener('click',()=>{state.mode=b.dataset.mode;render();scrollTo({top:0,behavior:'smooth'})}));render();
